#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *dq = (int*)malloc(N * sizeof(int)); // store indices
        int front = 0, back = -1;
        for (int i = 0; i < N; ++i) {
            // remove out‑of‑window indices
            if (front <= back && dq[front] <= i - X) front++;
            // maintain decreasing order
            while (front <= back && a[dq[back]] <= a[i]) back--;
            dq[++back] = i;
            if (i >= X - 1) {
                printf("%d", a[dq[front]]);
                if (i != N - 1) printf(" ");
            }
        }
        printf("\n");
        free(a); free(dq);
    }
    return 0;
}

